function reverseStr(s, k) {
    let chars = s.split("");
    for (let i = 0; i < chars.length; i += 2 * k) {
        let left = i;
        let right = Math.min(i + k - 1, chars.length - 1);
        while (left < right) {
            [chars[left++], chars[right--]] = [chars[right], chars[left]];
        }
    }
    return chars.join("");
}
```

